package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testSetPrettyPrinting() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially prettyPrinting should be false (DEFAULT_PRETTY_PRINT)
    Field prettyPrintingField = GsonBuilder.class.getDeclaredField("prettyPrinting");
    prettyPrintingField.setAccessible(true);
    boolean initialValue = (boolean) prettyPrintingField.get(builder);
    assertFalse(initialValue, "Initial prettyPrinting should be false");

    // Call setPrettyPrinting()
    GsonBuilder returnedBuilder = builder.setPrettyPrinting();

    // Verify it returns the same builder instance (this)
    assertSame(builder, returnedBuilder, "setPrettyPrinting should return the same builder instance");

    // Verify prettyPrinting is set to true
    boolean updatedValue = (boolean) prettyPrintingField.get(builder);
    assertTrue(updatedValue, "prettyPrinting should be set to true after setPrettyPrinting()");
  }
}
